// --- Security: SQL Query Validator ---

sealed trait ValidationError
case class ForbiddenOperation(detail: String) extends ValidationError
case class UnauthorizedTable(detail: String) extends ValidationError
case class QueryTooComplex(detail: String) extends ValidationError
case class ParseError(detail: String) extends ValidationError

object QueryValidator {

  // Allowlisted tables/views users can query
  private val allowedTables: Set[String] = Set(
    "analytics.page_views",
    "analytics.user_events",
    "analytics.sessions",
    "analytics.conversions",
    "reporting.daily_metrics",
    "reporting.weekly_summary"
  )

  // Forbidden SQL keywords/patterns that should never appear in user queries
  private val forbiddenPatterns: Seq[String] = Seq(
    "DROP", "DELETE", "UPDATE", "INSERT", "ALTER", "CREATE",
    "TRUNCATE", "GRANT", "REVOKE", "MERGE", "REPLACE",
    "INTO OUTFILE", "LOAD DATA", "CALL", "EXEC",
    "SET ", "RESET", "ADD JAR", "ADD FILE",
    "CREATE TEMPORARY FUNCTION", "CREATE FUNCTION",
    "UNCACHE", "CACHE", "REFRESH", "MSCK",
    "DESCRIBE", "SHOW DATABASES", "SHOW TABLES",
    // Prevent file-based data exfiltration
    "parquet.`", "csv.`", "json.`", "orc.`", "text.`",
    "jdbc(", "FORMAT_", "USING ",
    // Prevent UDF-based code execution
    "reflect(", "java_method(",
    // Prevent access to Hive internals
    "information_schema"
  )

  private val maxQueryLength = 5000
  private val maxResultRows = 10000

  def validate(query: String, userId: String): Either[ValidationError, String] = {
    for {
      _ <- checkQueryLength(query)
      _ <- checkForbiddenPatterns(query)
      _ <- checkIsSelectOnly(query)
      _ <- checkAllowedTables(query)
      sanitized <- Right(query.trim.stripSuffix(";"))
    } yield sanitized
  }

  private def checkQueryLength(query: String): Either[ValidationError, Unit] = {
    if (query.length > maxQueryLength)
      Left(QueryTooComplex(s"Query exceeds maximum length of $maxQueryLength characters"))
    else
      Right(())
  }

  private def checkForbiddenPatterns(query: String): Either[ValidationError, Unit] = {
    val upperQuery = query.toUpperCase.replaceAll("\\s+", " ")
    forbiddenPatterns.find(p => upperQuery.contains(p.toUpperCase)) match {
      case Some(pattern) =>
        Left(ForbiddenOperation(s"Query contains forbidden operation: pattern matched '$pattern'"))
      case None =>
        Right(())
    }
  }

  private def checkIsSelectOnly(query: String): Either[ValidationError, Unit] = {
    val trimmed = query.trim.toUpperCase
    // Only allow SELECT and WITH (CTE) statements
    if (trimmed.startsWith("SELECT") || trimmed.startsWith("WITH")) {
      Right(())
    } else {
      Left(ForbiddenOperation("Only SELECT queries are allowed"))
    }
  }

  private def checkAllowedTables(query: String): Either[ValidationError, Unit] = {
    Try {
      val plan = CatalystSqlParser.parsePlan(query)
      val referencedTables = extractTableReferences(plan)
      val unauthorized = referencedTables.filterNot(t => allowedTables.contains(t.toLowerCase))
      if (unauthorized.nonEmpty) {
        Left(UnauthorizedTable(s"Access denied to tables: ${unauthorized.mkString(", ")}. Allowed: ${allowedTables.mkString(", ")}"))
      } else {
        Right(())
      }
    } match {
      case Success(result) => result
      case Failure(ex) =>
        Left(ParseError(s"Failed to parse query for validation: ${ex.getMessage}"))
    }
  }

  private def extractTableReferences(plan: LogicalPlan): Set[String] = {
    plan.collect {
      case UnresolvedRelation(multipartIdentifier, _, _) =>
        multipartIdentifier.mkString(".")
    }.toSet
  }

  def effectiveMaxRows(requested: Option[Int]): Int = {
    requested.map(r => Math.min(r, maxResultRows)).getOrElse(maxResultRows)
  }
}

// --- Query Execution with Resource Limits ---

class SecureQueryExecutor(spark: SparkSession) {

  import spark.implicits._

  private val queryTimeoutMs: Long = 120000 // 2 minutes max

  def execute(validatedQuery: String, maxRows: Int, userId: String): QueryResponse = {
    val auditId = java.util.UUID.randomUUID().toString

    // Audit logging
    println(s"[AUDIT] id=$auditId user=$userId query=${validatedQuery.take(200)} timestamp=${System.currentTimeMillis()}")

    Try {
      // Set per-query resource constraints
      spark.conf.set("spark.sql.autoBroadcastJoinThreshold", "10485760") // 10MB
      spark.conf.set("spark.sql.shuffle.partitions", "50")

      // Wrap query with LIMIT to prevent unbounded results
      val limitedQuery = if (validatedQuery.toUpperCase.contains("LIMIT")) {
        validatedQuery
      } else {
        s"SELECT * FROM ($validatedQuery) __user_query LIMIT $maxRows"
      }

      val df: DataFrame = spark.sql(limitedQuery)

      // Convert to response format
      val rows = df.take(maxRows)
      val schema = df.schema
      val data = rows.map { row =>
        schema.fields.zipWithIndex.map { case (field, idx) =>
          val value: JsValue = if (row.isNullAt(idx)) {
            JsNull
          } else {
            field.dataType.typeName match {
              case "integer" | "long" | "short" | "byte" => JsNumber(row.getLong(idx))
              case "float" | "double" | "decimal" => JsNumber(BigDecimal(row.get(idx).toString))
              case "boolean" => JsBoolean(row.getBoolean(idx))
              case _ => JsString(row.get(idx).toString)
            }
          }
          field.name -> value
        }.toMap
      }.toList

      println(s"[AUDIT] id=$auditId status=SUCCESS rowCount=${data.size}")

      QueryResponse(
        status = "success",
        data = Some(data),
        error = None,
        rowCount = Some(data.size)
      )
    } match {
      case Success(response) => response
      case Failure(ex) =>
        println(s"[AUDIT] id=$auditId status=ERROR error=${ex.getMessage}")
        QueryResponse(
          status = "error",
          data = None,
          // Don't leak internal error details to users
          error = Some(sanitizeErrorMessage(ex.getMessage)),
          rowCount = None
        )
    }
  }

  private def sanitizeErrorMessage(msg: String): String = {
    // Remove file paths, class names, and stack trace info
    val sanitized = msg
      .replaceAll("/[\\w/]+\\.\\w+", "[path]")
      .replaceAll("\\b[a-z]+\\.[a-z]+\\.[A-Z]\\w+", "[class]")
      .take(500)
    s"Query execution failed: $sanitized"
  }
}

// --- Rate Limiter ---

class RateLimiter(maxRequestsPerMinute: Int) {
  private val requests = new java.util.concurrent.ConcurrentHashMap[String, java.util.concurrent.atomic.AtomicInteger]()
  private val windowStart = new java.util.concurrent.ConcurrentHashMap[String, Long]()

  def allow(userId: String): Boolean = {
    val now = System.currentTimeMillis()
    val start = windowStart.computeIfAbsent(userId, _ => now)

    if (now - start > 60000) {
      windowStart.put(userId, now)
      requests.put(userId, new java.util.concurrent.atomic.AtomicInteger(1))
      true
    } else {
      val counter = requests.computeIfAbsent(userId, _ => new java.util.concurrent.atomic.AtomicInteger(0))
      counter.incrementAndGet() <= maxRequestsPerMinute
    }
  }
}

