object SecureAnalyticsPlatform extends App {

  import JsonProtocol._

  implicit val system: ActorSystem = ActorSystem("analytics-platform")
  implicit val ec: ExecutionContext = system.dispatcher

  val spark = SparkSession.builder()
    .appName("Secure Analytics Platform")
    .config("spark.sql.warehouse.dir", "/data/warehouse")
    // Disable dangerous features
    .config("spark.sql.hive.thriftServer.singleSession", "true")
    .config("spark.sql.catalogImplementation", "in-memory")
    .enableHiveSupport()
    .getOrCreate()

  // Register only the views/tables users should access
  // In production, these would point to your data lake tables
  // spark.read.parquet("/data/lake/page_views").createOrReplaceTempView("analytics.page_views")
  // etc.

  val executor = new SecureQueryExecutor(spark)
  val rateLimiter = new RateLimiter(maxRequestsPerMinute = 30)

  val route =
    path("api" / "v1" / "query") {
      post {
        entity(as[QueryRequest]) { request =>
          // Authentication would happen via middleware/filter in production
          // Here we assume userId is validated upstream

          if (!rateLimiter.allow(request.userId)) {
            complete(StatusCodes.TooManyRequests -> QueryResponse(
              status = "error",
              data = None,
              error = Some("Rate limit exceeded. Please wait before submitting another query."),
              rowCount = None
            ))
          } else {
            QueryValidator.validate(request.query, request.userId) match {
              case Left(ForbiddenOperation(detail)) =>
                complete(StatusCodes.Forbidden -> QueryResponse("error", None, Some(detail), None))

              case Left(UnauthorizedTable(detail)) =>
                complete(StatusCodes.Forbidden -> QueryResponse("error", None, Some(detail), None))

              case Left(QueryTooComplex(detail)) =>
                complete(StatusCodes.BadRequest -> QueryResponse("error", None, Some(detail), None))

              case Left(ParseError(detail)) =>
                complete(StatusCodes.BadRequest -> QueryResponse("error", None, Some(detail), None))

              case Right(validatedQuery) =>
                val maxRows = QueryValidator.effectiveMaxRows(request.maxRows)
                val response = Future {
                  executor.execute(validatedQuery, maxRows, request.userId)
                }
                complete(response)
            }
          }
        }
      }
    } ~
    path("api" / "v1" / "tables") {
      get {
        // Let users discover what tables they can query
        val tables = QueryValidator.allowedTables.toList.sorted
        complete(JsObject("tables" -> JsArray(tables.map(JsString(_)).toVector)))
      }
    } ~
    path("health") {
      get {
        complete(StatusCodes.OK -> JsObject("status" -> JsString("healthy")))
      }
    }

  private val allowedTables: Set[String] = Set(
    "analytics.page_views",
    "analytics.user_events",
    "analytics.sessions",
    "analytics.conversions",
    "reporting.daily_metrics",
    "reporting.weekly_summary"
  )

  val bindingFuture = Http().newServerAt("0.0.0.0", 8080).bind(route)

  bindingFuture.onComplete {
    case Success(binding) =>
      println(s"Analytics Platform running at http://${binding.localAddress.getHostString}:${binding.localAddress.getPort}/")
    case Failure(ex) =>
      println(s"Failed to start server: ${ex.getMessage}")
      system.terminate()
  }
}